import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { SeedService } from '../../../data/seed.service';
import { AuthService } from '../../../core/services/auth.service';

type DocType = 'Submittal' | 'Drawing' | 'O&M Manual' | 'Quote';

interface PortalDoc {
  id: string;
  name: string;
  type: DocType;
  version: string;
  date: string;
}

interface DocVersion {
  version: string;
  date: string;
  note: string;
}

@Component({
  selector: 'app-portal-documents',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './portal-documents.component.html',
  styleUrl: './portal-documents.component.css',
})
export class PortalDocumentsComponent {
  // Inline, QES-scoped document library (illustrative, versioned).
  docs: PortalDoc[] = [
    { id: 'd-1', name: 'Volition Canyon — Submittal Package', type: 'Submittal', version: 'Rev 3', date: '2026-06-28' },
    { id: 'd-2', name: 'Data Hall B — Single-Line Drawing', type: 'Drawing', version: 'Rev 2', date: '2026-06-15' },
    { id: 'd-3', name: 'Emax 2 E6.2 — O&M Manual', type: 'O&M Manual', version: 'Rev 1', date: '2026-05-30' },
    { id: 'd-4', name: 'Budgetary Quote — 4x E6.2 4000A', type: 'Quote', version: 'Rev 1', date: '2026-07-02' },
    { id: 'd-5', name: 'SafeGear MV — Layout Drawing', type: 'Drawing', version: 'Rev 4', date: '2026-07-05' },
  ];

  // Version history shown for the submittal package.
  historyDoc = this.docs[0];
  history: DocVersion[] = [
    { version: 'Rev 3', date: '2026-06-28', note: 'Updated SafeGear feeder sections per RFI-014.' },
    { version: 'Rev 2', date: '2026-06-05', note: 'Incorporated XT6 42X spacing correction.' },
    { version: 'Rev 1', date: '2026-05-18', note: 'Initial submittal for review.' },
  ];

  constructor(public seed: SeedService, public auth: AuthService) {}

  typeBadge(type: DocType): string {
    switch (type) {
      case 'Submittal': return 'badge-info';
      case 'Drawing': return 'badge-neutral';
      case 'O&M Manual': return 'badge-success';
      case 'Quote': return 'badge-warning';
      default: return 'badge-neutral';
    }
  }

  download(): void {
    // No-op: mockup download.
  }
}
